/** Get frame by ID */
export function getFrameById(id) {
    return FRAMES.find(f => f.id === id) || null;
}

/** Get frames by category */
export function getFramesByCategory(category) {
    if (!category || category === 'all') return FRAMES;
    return FRAMES.filter(f => f.category === category);
}

/** Search frames by title */
export function searchFrames(query) {
    if (!query) return FRAMES;
    const q = query.toLowerCase();
    return FRAMES.filter(f => f.title.toLowerCase().includes(q) || f.id.toLowerCase().includes(q));
}

/** Get full image path for a frame */
export function getFrameImagePath(frame) {
    const basePath = window.OmnexConfig?.basePath || '';
    return `${basePath}/${FRAMES_BASE_PATH}${frame.frameFile}`;
}

/** Get thumbnail path for a frame */
export function getFrameThumbPath(frame) {
    const basePath = window.OmnexConfig?.basePath || '';
    const thumbFile = frame.id + '.png';
    return `${basePath}/${THUMBS_BASE_PATH}${thumbFile}`;
}
